static common_chat_params common_chat_templates_apply_jinja(
    const struct common_chat_templates * tmpls,
    const struct common_chat_templates_inputs & inputs) {

    // Step 1: Prepare generation_params
    autoparser::generation_params params;
    params.tools = common_chat_tools_to_json_oaicompat(inputs.tools);

    // Step 2: Select template (default or tool_use variant)
    const auto & tmpl = 
        params.tools.is_array() && tmpls->template_tool_use ? 
        *tmpls->template_tool_use : 
        *tmpls->template_default;

    // Step 3: Render messages to JSON format
    params.messages = render_message_to_json(inputs.messages, tmpl.original_caps());

    // Step 4: Apply message transformations based on template capabilities
    if (tmpl.original_caps().supports_tool_calls) {
        workaround::requires_non_null_content(params.messages);
    }
    if (tmpl.original_caps().supports_object_arguments) {
        workaround::func_args_not_string(params.messages);
    }

    // Step 5: Calculate generation prompt (difference between with/without add_generation_prompt)
    std::string no_gen_prompt = common_chat_template_direct_apply_impl(tmpl, params_without_gen);
    std::string gen_prompt = common_chat_template_direct_apply_impl(tmpl, params_with_gen);
    params.generation_prompt = calculate_diff_split(no_gen_prompt, gen_prompt).right;

    // Step 6: Try specialized handlers first
    if (auto result = common_chat_try_specialized_template(tmpl, src, params)) {
        return *result;  // Use specialized handler
    }

    // Step 7: Fall back to auto-parser for generic templates
    struct autoparser::autoparser ap;
    ap.analyze_template(tmpl);
    auto auto_params = autoparser::peg_generator::generate_parser(tmpl, params, ap);
    return auto_params;
}
```

